export const UnitStatusSchema = z.enum(["rough","parsed","user_verified","stale"]).describe("Per-unit crystallization state (§6.0/§2.4) — distinct from `MathExpression.parse_status`\n(surface renderability) and from `ObjectStatus` (object lifecycle).");

export const UnitTypeSchema = z.enum(["theorem","lemma","proposition","corollary","definition","conjecture","claim","question","proof","proof_step","motivation","intuition","idea","proof_idea","remark","observation","warning","analogy","application","open_issue","return_later","note","example"]).describe("THE one user-facing math-flow label of a unit (§6.0). Carries *force and meaning*;\nform lives separately in `UnitContent.kind`. Absent (`Option::None`) = plain content.\nForms (list/group/embed/derivation/case_split) are deliberately NOT here — they are\ncontent kinds, never types (§6.0b).");

export const ValidationErrorSchema = z.union([z.object({ "given": z.string(), "code": z.literal("unknown_object_type") }), z.object({ "field": z.string(), "code": z.literal("invalid_id") }), z.object({ "field": z.string(), "code": z.literal("not_uuid_v7") }).describe("Client-minted ids must be UUIDv7 (arch doc §4/§6.3 — sortable, client-mintable)."), z.object({ "max_chars": z.number().int().gte(0), "given_chars": z.number().int().gte(0), "code": z.literal("title_too_long") }), z.object({ "max_bytes": z.number().int().gte(0), "given_bytes": z.number().int().gte(0), "code": z.literal("raw_source_too_large") }), z.object({ "origin": z.enum(["user","ai","imported","system"]).describe("Provenance origin (arch doc §6.1). Stable, complete set; only `User` and `System`\nare producible until the AI/import provenance columns land with their slices."), "code": z.literal("missing_created_by") }).describe("First §6.1a origin-field invariant: `created_by` is required when origin = user."), z.object({ "origin": z.enum(["user","ai","imported","system"]).describe("Provenance origin (arch doc §6.1). Stable, complete set; only `User` and `System`\nare producible until the AI/import provenance columns land with their slices."), "code": z.literal("origin_not_producible") }).describe("AI/import provenance is structurally impossible until its columns land (§6.1)."), z.object({ "expected": z.number().int().gte(0), "given": z.number().int().gte(0), "code": z.literal("schema_version_mismatch") }), z.object({ "given": z.number().int().gte(0), "current": z.number().int().gte(0), "code": z.literal("schema_version_from_the_future") }).describe("A stored value claims a schema_version newer than this core understands —\nrefusing loudly beats misreading user data (§2.2)."), z.object({ "given": z.number().int().gte(0), "code": z.literal("link_target_not_exactly_one") }).describe("A `links` row must set exactly one target arm. Slice 1's arms are\n`{target_object_id, unresolved_text}`; `given` is how many were set (§6.1a/§6.1b)."), z.object({ "code": z.literal("off_graph_deliberate_edge") }).describe("A deliberate edge (`from_content = false`) carries no object target — the typed\nknowledge graph stays object-only, no off-graph deliberate edges (§6.1a)."), z.object({ "code": z.literal("unit_target_without_object") }).describe("`target_unit_id` is set without `target_object_id` — a unit refinement requires\nits owning object target (§6.1a composite-FK discipline)."), z.object({ "link_type": z.enum(["related","proves","uses","source_for","example_of","counterexample_to","application_of","motivated_by","answers","generalizes","special_case_of","equivalent_to","questions","element_of","subset_of","equals"]).describe("Typed relationship of a `links` edge (§6.1b). Most are deliberate graph edges\n(object-target, §6.1a); `related`/content-derived rows may stay unresolved."), "code": z.literal("typed_edge_requires_object_target") }).describe("A typed graph edge resolved to a non-object target (notation/source/unresolved) —\nevery graph edge type requires an object target (§6.1a/§6.1b)."), z.object({ "code": z.literal("selector_without_object_target") }).describe("`target_selector` is set without `target_object_id` — a selector refines an object\ntarget, never substitutes for one (§6.1a)."), z.object({ "column": z.string(), "content_tag": z.string(), "code": z.literal("content_kind_mismatch") }).describe("The derived `content_kind` would disagree with the unit's `content` tag (one fact,\none home — the generated column must equal the union tag, §6.0b)."), z.object({ "slot": z.string(), "parent_kind": z.string(), "code": z.literal("invalid_slot_for_parent_kind") }).describe("A unit's `slot` is not valid for its parent's content kind (§6.0b/§6.1a)."), z.object({ "code": z.literal("example_kind_without_example_type") }).describe("`example_kind` is set on a unit whose `type` is not `example` (§6.0b)."), z.object({ "expected": z.enum(["note","theorem","lemma","proposition","corollary","conjecture","claim","definition","proof","example","question","source_excerpt","trail","annotation","journal_day"]).describe("Durable workspace identity of an object (arch doc §6.0b: `object.type` ≠ `unit.type`).\nSlice 1 widens this from the skeleton's lone `note` to the full §6 vocabulary: the\nformal family (theorem/lemma/proposition/corollary/conjecture/claim), definition,\nproof, example, question — all producible via create — plus source_excerpt, trail,\nannotation, journal_day, which are **reserved vocabulary** (valid on read, not yet\nproducible — their detail tables / surfaces land in later slices, §6.1a/§13a)."), "given": z.enum(["note","theorem","lemma","proposition","corollary","conjecture","claim","definition","proof","example","question","source_excerpt","trail","annotation","journal_day"]).describe("Durable workspace identity of an object (arch doc §6.0b: `object.type` ≠ `unit.type`).\nSlice 1 widens this from the skeleton's lone `note` to the full §6 vocabulary: the\nformal family (theorem/lemma/proposition/corollary/conjecture/claim), definition,\nproof, example, question — all producible via create — plus source_excerpt, trail,\nannotation, journal_day, which are **reserved vocabulary** (valid on read, not yet\nproducible — their detail tables / surfaces land in later slices, §6.1a/§13a)."), "code": z.literal("detail_type_mismatch") }).describe("A `*_detail.object_id` references an object of the wrong type (§6.1a\ntype-qualified references)."), z.object({ "object_type": z.enum(["note","theorem","lemma","proposition","corollary","conjecture","claim","definition","proof","example","question","source_excerpt","trail","annotation","journal_day"]).describe("Durable workspace identity of an object (arch doc §6.0b: `object.type` ≠ `unit.type`).\nSlice 1 widens this from the skeleton's lone `note` to the full §6 vocabulary: the\nformal family (theorem/lemma/proposition/corollary/conjecture/claim), definition,\nproof, example, question — all producible via create — plus source_excerpt, trail,\nannotation, journal_day, which are **reserved vocabulary** (valid on read, not yet\nproducible — their detail tables / surfaces land in later slices, §6.1a/§13a)."), "code": z.literal("type_not_producible_yet") }).describe("The create path cannot produce this object type yet (reserved vocabulary whose\nowning machinery lands in a later slice, §6.1a/§13a)."), z.object({ "given": z.number().int().gte(0), "code": z.literal("tagging_target_not_exactly_one") }).describe("A `taggings` row must target exactly one of {object, unit}; `given` is how many\nwere set (§6.0b)."), z.object({ "scope": z.enum(["global","space","source","trail","local"]).describe("The scope an alias is valid in (§6.3b); paired with `scope_ref` (§6.1a consistency)."), "code": z.literal("alias_scope_ref_mismatch") }).describe("An alias's `scope` and `scope_ref` are inconsistent (§6.1a scope ↔ scope_ref)."), z.object({ "given": z.number().int().gte(0), "code": z.literal("handle_target_not_exactly_one") }).describe("A `handles` row must set exactly one refinement of {unit, expression}; `given` is\nhow many were set (§6.3b/§6.1a)."), z.object({ "code": z.literal("declared_by_ai") }).describe("`declared_by = ai` is structurally forbidden: AI proposals are review_items, never\ncanonical units; acceptance enters as `user` (§3.9/§6.0).")]).describe("A domain validation failure. Errors are VALUES crossing the FFI (result envelopes),\nnever exceptions (arch doc §17 boundary discipline).");

